   309→    /** Look up a word - ported from renderer.js showWordInline() */
   310→    fun lookupWord(word: String) {
   311→        _uiState.update { it.copy(showWordCard = true, wordCardData = WordCardData(word = word, translation = "查询中...")) }
   312→        speak(word)
   313→
   314→        viewModelScope.launch(Dispatchers.IO) {
   315→            val lang = _uiState.value.currentLang
   316→            val context = _uiState.value.currentSentence
   317→
   318→            // Parallel lookups
   319→            val aiConfig = aiConfigStore.config.first()
   320→            val aiTransPromise = launch { aiTranslateWord(word, context, lang, aiConfig) }
   321→
   322→            val cardData = when (lang) {
   323→                "en" -> {
   324→                    val online = dictionaryService.lookupEnglish(word)
   325→                    val translation = dictionaryService.translate(word, "en")
   326→                    val aiTrans = aiTranslateWord(word, context, lang, aiConfig)
   327→                    WordCardData(
   328→                        word = word,
   329→                        phonetic = online?.phonetic ?: "",
   330→                        translation = aiTrans ?: translation ?: online?.translation ?: "未找到释义",
   331→                        definitions = online?.definitions ?: emptyList(),
   332→                        examples = online?.examples ?: emptyList()
   333→                    )
   334→                }
   335→                "ja" -> {
   336→                    val online = dictionaryService.lookupJapanese(word)
   337→                    val translation = dictionaryService.translate(word, "ja")
   338→                    val aiTrans = aiTranslateWord(word, context, lang, aiConfig)
   339→                    WordCardData(
   340→                        word = word,
   341→                        phonetic = online?.phonetic ?: "",
   342→                        translation = aiTrans ?: translation ?: "未找到释义",
   343→                        definitions = online?.definitions ?: emptyList()
   344→                    )
   345→                }
   346→                else -> {
   347→                    val translation = dictionaryService.translate(word, lang)
   348→                    val aiTrans = aiTranslateWord(word, context, lang, aiConfig)
   349→                    WordCardData(
   350→                        word = word,
   351→                        translation = aiTrans ?: translation ?: "未找到释义"
   352→                    )
   353→                }
   354→            }
   355→            _uiState.update { it.copy(wordCardData = cardData) }
   356→        }
   357→    }
