   359→    private suspend fun aiTranslateWord(word: String, context: String, lang: String, config: AIConfig): String? {
   360→        val langName = LANGUAGES.find { it.code == lang }?.name ?: "英语"
   361→        val prompt = "将${langName}「${word}」翻译为中文。${if (context.isNotBlank()) "语境:\"$context\"。" else ""}只回复中文释义，多义项用/分隔，不要音译。"
   362→        return aiService.chat(config, prompt)
   363→    }
