   421→    /** Get aligned word timings for current cue */
   422→    fun getAlignedTimings(words: List<String>): List<WordTimestamp?> {
   423→        val state = _uiState.value
   424→        val cueIdx = state.currentCueIndex
   425→        if (cueIdx < 0 || cueIdx >= state.subtitles.size || state.wordTimings.isEmpty()) {
   426→            return List(words.size) { null }
   427→        }
   428→        val cue = state.subtitles[cueIdx]
   429→        return WordAligner.alignWords(words, state.wordTimings, cue.startMs / 1000.0, cue.endMs / 1000.0)
   430→    }
   431→
   432→    /** Format remaining time for display */
   433→    private fun formatRemainingTime(seconds: Long): String {
   434→        return when {
   435→            seconds < 60 -> "${seconds}秒"
   436→            seconds < 3600 -> "${seconds / 60}分${seconds % 60}秒"
   437→            else -> "${seconds / 3600}小时${(seconds % 3600) / 60}分"
   438→        }
   439→    }
