   584→/**
   585→ * 下载进度卡片组件
   586→ */
   587→@Composable
   588→private fun DownloadProgressCard(
   589→    task: DownloadTask,
   590→    onCancel: () -> Unit,
   591→    formatFileSize: (Long) -> String,
   592→    formatSpeed: (Long) -> String,
   593→    formatRemainingTime: (Long) -> String,
   594→    getStatusText: (DownloadStatus) -> String
   595→) {
   596→    Card(
   597→        modifier = Modifier.fillMaxWidth(),
   598→        colors = CardDefaults.cardColors(
   599→            containerColor = when (task.status) {
   600→                DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.errorContainer
   601→                DownloadStatus.WAITING_FOR_AUTH -> MaterialTheme.colorScheme.tertiaryContainer
   602→                else -> MaterialTheme.colorScheme.primaryContainer
   603→            }
   604→        )
   605→    ) {
   606→        Column(modifier = Modifier.padding(16.dp)) {
   607→            // 标题和状态
   608→            Row(
   609→                modifier = Modifier.fillMaxWidth(),
   610→                horizontalArrangement = Arrangement.SpaceBetween,
   611→                verticalAlignment = Alignment.CenterVertically
   612→            ) {
   613→                Column(Modifier.weight(1f)) {
   614→                    Text(
   615→                        task.title,
   616→                        style = MaterialTheme.typography.titleSmall,
   617→                        maxLines = 1,
